module top_module(i_clk, i_async, o_sync);input i_clk; 
  input i_async; 
  output o_sync; 
  reg async_sampled; 
  reg o_sync; 
  initial begin 
  async_sampled <= 1'b0; 
  o_sync <= 1'b0; 
  end 
  always @( posedge i_clk ) 
  async_sampled <= i_async; 
  always @( negedge i_clk ) 
  o_sync <= async_sampled; 
 endmodule
